SELECT

FROM system_announcement
WHERE deleted = 0

    AND type = #{type,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND status = #{status,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM system_announcement
WHERE deleted = 0

    AND type = #{type,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND status = #{status,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
